import React from "react";
import requests from "../requests";
import { Link } from "react-router-dom";
import { useMediaQuery } from "react-responsive";
import { FaStar } from "react-icons/fa";

function MovieCard({ movie, isLarge, mediaType }) {
  // extract movie infos
  const backdrop_path = requests.image_api + movie.backdrop_path;
  const poster_path = requests.image_api + movie.poster_path;
  const poster_path_for_phone = requests.small_image_api + movie.poster_path;
  const { id, title, vote_average } = movie;
  const isPhone = useMediaQuery({ query: "(max-width:460px)" });
  const Comp = (
    <div className={isLarge ? "MovieCardLarge" : "MovieCard"}>
      <Link
        to={`/all-about/${movie.media_type ? movie.media_type : mediaType}/${
          movie.id
        }`}
      >
        <img
          src={
            isLarge
              ? backdrop_path
              : isPhone
              ? poster_path_for_phone
              : poster_path
          }
          alt={title}
          key={id}
          data-mediatype={movie.media_type}
        />
      </Link>
      <h4 className="voteAvarage">
        <span>{movie.media_type ? movie.media_type : mediaType}</span>
        <span style={{ display: "flex", alignItems: "center" }}>
          {vote_average > 0 ? vote_average.toString().substring(0, 3) : "UV"}{" "}
          <FaStar style={{ marginLeft: ".2em" }} />
        </span>
      </h4>
    </div>
  );
  if (movie.poster_path === null || movie.poster_path === undefined)
    return false;
  return Comp;
}

export default MovieCard;
