import React, { useState, useEffect } from "react";
import MovieCard from "./MovieCard";
import axios from "axios";
import requests from "../requests";
import { IoCheckmarkDoneCircle } from "react-icons/io5";
import { MdOutlineContentCopy } from "react-icons/md";
import CopyToClipboard from "react-copy-to-clipboard";

function WatchList({ watchList, SetWatchList, watchListLen, setWatchListLen }) {
  const [myMovies, setmyMovies] = useState([]);
  const collector = [];

  const doneHandler = (id) => {
    const newList = watchList.filter((movieIn) => movieIn.movieId !== id);
    const newmovielist = myMovies.filter((movie) => movie.id !== id);
    SetWatchList(newList);
    setmyMovies(newmovielist);
    localStorage.setItem("watchlist", JSON.stringify(newList));
    setWatchListLen(watchListLen--);
  };

  const fetchIt = async (type, id) => {
    const res = await axios.get(
      `https://api.themoviedb.org/3/${type}/${id}?api_key=${requests.apiKey}`
    );
    collector.push({ ...res.data, media_type: type });
    setmyMovies([...collector]);
  };

  useEffect(() => {
    watchList.map((movie) => {
      fetchIt(movie.mediaType, movie.movieId);
    });
  }, []);

  return (
    <div className="watch_list">
      <div className="inner_watch_list">
        {myMovies.map((movie, key) => (
          <div className="movie_card_in_watch_list_holder" key={key}>
            <MovieCard
              movie={movie}
              isLarge={false}
              mediaType={movie.media_type}
              key={key}
            />
            <span id="done">
              <CopyToClipboard
                text={
                  window.location.host +
                  "/#/all-about/" +
                  movie.media_type +
                  "/" +
                  movie.id
                }
              >
                <MdOutlineContentCopy
                  className="copyToClipBoardButton"
                  onClick={(e) => (e.target.style.opacity = "0.5")}
                />
              </CopyToClipboard>

              <IoCheckmarkDoneCircle
                className="done-button"
                onClick={() => doneHandler(movie.id)}
              />
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}

export default WatchList;
