import axios from "axios";
import React, { useEffect, useState } from "react";
import requests from "../requests";
import CastCard from "./CastCard";
import Slider from "react-slick";
import { useMediaQuery } from "react-responsive";

function Casts({ type, id }) {
  const [casts, setcasts] = useState([]);
  const isBigScreen = useMediaQuery({ query: "(min-width: 790px)" });
  const settings = {
    dots: false,
    speed: 500,
    slidesToShow: 4,
    slidesToScroll: 4,
    initialSlide: 0,
    variableWidth: true,
    adaptiveHeight: true,
    infinite: false,
    focusOnSelect: true,
    arrows: true,
  };
  useEffect(() => {
    const fetchIt = async () => {
      const res = await axios.get(
        `https://api.themoviedb.org/3/${type}/${id}/credits?api_key=${requests.apiKey}`
      );
      setcasts(res.data.cast.slice(0, 7));
    };
    fetchIt();
  }, [id, type]);
  return (
    <div className="row">
      <h2>Casts</h2>
      {isBigScreen ? (
        <Slider {...settings}>
          {casts.map((cast, key) => (
            <CastCard
              name={cast.name}
              id={cast.id}
              profile_path={cast.profile_path}
              popularity={cast.popularity}
              key={key}
              credit_id={cast.credit_id}
            />
          ))}
        </Slider>
      ) : (
        <div className="row__posters">
          {casts.map((cast, key) => (
            <CastCard
              name={cast.name}
              id={cast.id}
              profile_path={cast.profile_path}
              popularity={cast.popularity}
              key={key}
              credit_id={cast.credit_id}
            />
          ))}
        </div>
      )}
    </div>
  );
}

export default Casts;
